var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"날마다 나쁜 꿈을 꾼다네.","JPN":"毎日悪夢を見るのだ。","ENG":"Every night, I find myself trapped in the same wretched dream.","TWN":"我每天都會做惡夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_1"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"얼굴 모를 한 여인이 눈 앞에서 죽어가는 꿈이요.","JPN":"見知らぬ女性が目の前で死んでゆく夢でな。","ENG":"A woman whose face I do not recognize, dying right before my eyes.","TWN":"夢裡有個陌生女子在我眼前死去。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_2"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"여인은 제 목을 노리는 커다란 범과 마주하고 있으나, 내가 아무리 손을 뻗어도 닿지 않아.","JPN":"その女性は己の首を狙う大きな虎と向かい合っているのだが、某がいくら手を伸ばそうとも、まったく届かなくでな。","ENG":"A great tiger stands before her, poised for her throat, yet no matter how far I reach, I can't touch her.","TWN":"女人與虎視眈眈的老虎搏鬥，但無論我怎麼伸手，就是觸不到她。"},"stage":{"bg":"MS_1501_1","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_3"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 뒤를 돌아 나를 바라볼 즈음이면, 만개하듯 번지는 핏자국에 눈앞이 붉게 질려.","JPN":"その女性が振り返り某に目を向けると、飛び散る血しぶきに視野が埋め尽くされる。","ENG":"By the time she turns and looks my way, my vision is already stained red with blood spreading like petals.","TWN":"當她回頭望向我時，眼前便被大片的血跡給染得一片猩紅。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_4"},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 꿈에서 깨어나면, 뜻 모를 공허함이 새벽 안개처럼 밀려들어 숨통을 갑갑하게 조여오지.","JPN":"そうやって夢から覚めると、訳の分からぬ虚しさが夜明けの霧のごとく押し寄せ、息が苦しくなるのだ。","ENG":"And when I wake, that nameless emptiness creeps in like the dawn mist, pressing down on my chest.","TWN":"當我從夢裡驚醒後，一股莫名的空虛感如早晨的濃霧般襲來，緊緊地掐住我的喉嚨。"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_5"},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그 차오르는 갑갑함을 못 이겨 꼭두새벽의 거리를 내달리지만 변하는 건 없어.","JPN":"湧き上がるもどかしさに耐えきれず、早朝の街をがむしゃらに走っても、変わるものは何もない。","ENG":"To shake it off, I run through the streets before sunrise, but nothing ever changes.","TWN":"我無法忍受這股窒息感，於是在大清早地奪門而出，但卻沒有任何改變。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_6"},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"다음 날도, 또 그 다음 날도 같은 꿈을 꾸리란 것을… 나는 알고 있기 때문에.","JPN":"次の日も、その次の日も同じ夢を見るであろうことを……某は知っているからだ。","ENG":"I know well that tomorrow, and the day after, I'll encounter that same dream again.","TWN":"因為我知道，明天、後天，甚至是之後的每一天…我都會做相同的夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_7"},{"id":"L19_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"가! 가! 빨리!","JPN":"急げ！　早く！","ENG":"Go! Go! Move it!","TWN":"動作快！快走！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BIKE_01"},{"id":"L20_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"제대로 털었겠지?","JPN":"ちゃんと持ってきたんだろうな？","ENG":"We cleaned 'em out, right?","TWN":"東西都有拿到吧？"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"걱정 마. 샤레이드로 떠나서 떵떵거리며 살 만큼은 털었으니까.","JPN":"問題ないよ。シャレードで何不自由なく生きていけるぐらいは詰めたから。","ENG":"Relax. We've got enough to live large in Charade for years.","TWN":"放心吧，這些夠我們在查雷德過上衣食無憂的好日子。"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"어이, 경찰들 따라붙었어! 곧 잡히겠는데?","JPN":"おい、警察が追って来てるぞ！　このままだと捕まるぞ！","ENG":"Hey, we got cops on our tail! They're closing in!","TWN":"喂！警察追上來了！不太妙！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"걱정 말고 계속 밟아. 작전대로만 해.","JPN":"気にせず加速しろ。作戦通りにやりゃいいんだ。","ENG":"Don't sweat it! Just keep driving, stick to the plan.","TWN":"沒事，繼續踩油門，照計劃進行！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"이봐. 교량 앞에 차단기 내려가 있잖아! 여기로 가는 거 맞아?","JPN":"なんだ、橋の前の遮断機が降りてるじゃないか！　本当にこっちで合ってるのか？","ENG":"Hey, the crossing gate's down up ahead! You sure we're going the right way?","TWN":"喂，你看！橋上的柵欄降下來了，確定是走這嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"미친…! 이거 도개교잖아! 화물선이 오고 있다고!","JPN":"やばいよ……！　これ跳ね橋じゃん！　貨物船が近づいてくる！","ENG":"Damn it…! It's a drawbridge! There's a cargo ship coming through!","TWN":"該死…！那是開啟橋！有貨船要經過！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"쫄지 마! 멈추면 우리 다 끝장이라 생각해!","JPN":"ビビんな！　ここで止まったら俺たちは終わりだ！","ENG":"Don't chicken out! If we stop now, we're screwed for good!","TWN":"別緊張！停下來我們就死定了！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"젠장, 밟는다!","JPN":"くそっ、飛ばすぞ！","ENG":"Damn it, hold tight!","TWN":"可惡，油門催到底！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼… "},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"살았다. 조금만 늦었어도 추락할 뻔했어.","JPN":"危なかったな。一足遅かったら落ちるところだった。","ENG":"We made it. One second later and we'd have gone down with it.","TWN":"好險，差點就要掉進河裡了。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"하핫, 거 봐! 내가 뭐랬어! 될 거라고 했지!","JPN":"ははっ！　だから言ったじゃねえか！　気にするなってな！","ENG":"Haha! See? I told you we'd make it!","TWN":"哈哈，看吧！我怎麼說的？就說沒問題吧！"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"경찰 놈들. 잔뜩 몰려와 놓고 닭 쫓던 개 신세구만.","JPN":"警察のやつら、俺たちが逃げるのを指咥えて見てるしかないね。","ENG":"Look at all those cops. Just a bunch of dogs that lost their prey.","TWN":"那些臭警察，這麼多人來追我們，結果白忙一場。"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"응…?","JPN":"ん……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"저 바이크… 뭐하는 거지?","JPN":"あのバイク……何をしてるんだ？","ENG":"What's… that bike doing?","TWN":"那台摩托車…要幹嘛？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"바이크라고?","JPN":"バイクだあ？","ENG":"Bike?","TWN":"摩托車？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"뭐야, 저거? 교량이 올라가는데 왜 속도를 점점 올리지? 설마…?","JPN":"何だ、あれ？　橋が上がってくのにどんどんスピード出して……？　まさか……？","ENG":"What the? The bridge is up and he's speeding up? No way…","TWN":"他幹嘛？橋都升起來了，為什麼還一直加速？他該不會…？"},"stage":{"bg":"DONGDAEMUN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"너… 넘었다! 이쪽으로 넘어왔어!","JPN":"と……飛び越えたぞ！　こっちに渡って来た！","ENG":"H-he cleared it! He jumped over!","TWN":"他…衝過來咧！他衝過那座橋了！"},"stage":{"bg":"DONGDAEMUN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BIKE_01"},{"id":"L47_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"걱정 마. 왜 우릴 쫓아오는진 몰라도…","JPN":"心配すんな。なんで俺たちを追ってくるのか知らねえが……","ENG":"Don't worry. I don't know why he's after us but–","TWN":"安啦！雖然不知道他幹嘛要追我們…"},"stage":{"bg":"DONGDAEMUN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"바이크쯤이야 그냥 쏴버리면 그만이지!","JPN":"あんなバイクなんか、撃っちまえばいい！","ENG":"It's just a bike. Shoot him and he's done!","TWN":"但不過就一台摩托車，直接開炮就好啦！"},"stage":{"bg":"DONGDAEMUN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"얌마! 그건 헬기가 뜨면 쓰려던 건데…!","JPN":"おい！　それは対ヘリ用の……！","ENG":"Hey! That was for the chopper…!","TWN":"喂！那是直升機出現時要用的…！"},"stage":{"bg":"DONGDAEMUN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"죽어라!","JPN":"死ね！","ENG":"Die!","TWN":"去死吧！"},"stage":{"bg":"DONGDAEMUN","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"이 미친 자식! 하마터면 뒤에 있는 우리도 휘말릴 뻔했잖아!","JPN":"バカ野郎！　後ろにいる俺たちまで巻き添え食うところだったじゃないか！","ENG":"You crazy bastard! You almost blew us up too!","TWN":"你這個瘋子！差點還波及到我們！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"그, 그래도 효과는 확실한데? 이 정도 폭발이라면 무사하진 못할…","JPN":"で、でも効果はあったみたいだよ？　この爆発ならただじゃすま……","ENG":"Y-yeah, but it worked, right? He couldn't have survived that bla–","TWN":"不過…效果確實不錯。我就不信這麼猛烈的爆炸他還能活…"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"…어? 갈고리?","JPN":"……え？　フック？","ENG":"…Huh? A hook?","TWN":"…嗯？鉤子？"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"우와악!! 저게 뭐야!","JPN":"うわああっ！！　なんだあれ！","ENG":"Whoa!! What the heck is that?!","TWN":"哇咧！那是什麼！"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_09"},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그래플링 건, 팔콘 훅 MK-3.","JPN":"グラップルガン、ファルコンフックMK-3。","ENG":"Grappling gun, Falcon Hook MK-3.","TWN":"鉤抓槍，獵鷹鉤爪 MK-3。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"회사에서 개발 중인 건설 보조 장비요. 시제품이지만 안정성은 합격점이군.","JPN":"弊社で開発中の建設補助装置である。試作品だが、安定性は合格点のようだ。","ENG":"An experimental construction device my company's developing. Still a prototype, but stable enough, it seems.","TWN":"是公司開發中的建築輔助工具。雖然只是樣品，但已經通過穩定性測試。"},"stage":{"bg":"TEHERANRO_DAYTIME","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"건설 장비라고…?","JPN":"建設装置だと……？","ENG":"Construction device…?","TWN":"建築工具…？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"너 대체 뭐하는 놈이야! 경찰도 아니면서 왜 우릴 쫓아와서 방해하는 거냐고!","JPN":"てめぇ、いったい何もんだ！　警察でもねえくせになんで俺たちの後をつけて邪魔すんだよ！","ENG":"Who the heck are you?! You're not a cop, so why chase us?!","TWN":"你到底是誰！你又不是警察，幹嘛追著我們不放！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"프로핏 인더스트리 개발전문 4팀의 서생일세.","JPN":"某はプロフィットインダストリー開発専門4チームのショウという。","ENG":"Seosaeng from Development Team 4, Profit Industry.","TWN":"我是普羅菲特工業開發部第4組的書生。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"마침 출근길이 같은 방향이기도 하고, 몇 가지를 시험해볼 수 있을 것 같아서 말이야.","JPN":"ちょうど出勤中のところ、方向も同じだったので、いくつか試させてもらおうと思ってな。","ENG":"Happened to be headed the same way on my commute. Thought I'd test a few things along the way.","TWN":"剛好和去公司的路同方向，所以就順便試幾樣東西。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"뭐…? 또 뭘 시험해?","JPN":"は……？　な、何を試そうってんだ？","ENG":"What…? Tests?","TWN":"什麼…？又要試什麼？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이건, 경찰에 납품할 예정인 진압봉 PM-C7일세.","JPN":"これは警察に納品予定の警棒、PM-C7なんだが。","ENG":"This here's the PM-C7 baton. Meant for the police, once it's approved.","TWN":"這是準備供貨給警方的鎮壓警棍PM-C7。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"멍청아! 설명 듣지 마…! 일단 쏴 버려!","JPN":"おい、説明なんて聞いている場合か……！　早く撃ってしまえ！","ENG":"Hey, don't just stand there…! Shoot him!","TWN":"喂，別聽他廢話！給我開槍！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"우아악! 저, 저 개자식…! 총알을 내 쪽으로 튕겨냈어!","JPN":"うああ！　あ、あいつ……！　弾をこっちに弾き返したよ！","ENG":"Agh! That bastard…! He just deflected the bullets back at me!","TWN":"哇咧！那傢伙…！子彈彈回到我這裡來了！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…방탄 성능, 양호.","JPN":"……防弾性能、良好。","ENG":"…Ballistic durability. Good enough.","TWN":"……防彈功能，良好。"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"오… 오지 마!","JPN":"く……来るんじゃねえ！","ENG":"D-don't come… any closer!","TWN":"別…別過來！"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다음은… 전기충격 기능을 시험하지.","JPN":"お次は……電気衝撃機能を試してみるか。","ENG":"Next… I should test the stun feature.","TWN":"接下來，測試電擊功能。"},"stage":{"bg":"VEHICLE","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_ELECTRIC"},{"id":"L42_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"저기, 서생 씨?","JPN":"ちょっと、ショウくん？","ENG":"Hey, Seosaeng?","TWN":"那個，書生博士？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"오늘 무슨 일 있었어? 회사 앞에서 경찰이랑 얘기 나누던데.","JPN":"今日何かあった？　会社の前で警察と話してたでしょ。","ENG":"What happened today? I saw you talking to cops outside.","TWN":"今天發生什麼事了嗎？剛才看你在公司門口和警察說話。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"별 일 아닐세. 꿈자리가 사나워 기분 전환이 필요하던 참이라.","JPN":"大したことではない。昨晩の夢見が悪くて、ちょうど気晴らしでもしたいところだったのだ。","ENG":"Think nothing of it. Just clearing my head after a restless night.","TWN":"沒什麼。只是做了個惡夢，需要透透氣。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"기분 전환…? 사고 친 거 아니지?","JPN":"気晴らし……？　何かやらかしてないよね？","ENG":"Clearing your head…? You didn't cause any trouble, right?","TWN":"透氣…？該不會是闖禍了吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_B","text":{"KOREA":"사고랑 비슷한 급인 거 같은데요? 지금 서생 박사님 얼굴, 뉴스에 나오고 있어요.","JPN":"やらかしたと言っても過言ではないみたいですよ。今、ニュースにショウ博士の顔映ってますしね。","ENG":"Looks pretty close to trouble to me. Your face is on the news, you know.","TWN":"似乎就是闖禍了。博士的臉正出現在新聞上。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"보석점 강도 3인방… 바이크로 추격해온 카운터에게 일망타진…?","JPN":"宝石店を襲った強盗3人組……バイクで追撃してきたカウンターによって一網打尽……？","ENG":"Three jewelry store robbers… All down thanks to a biker Counter…?","TWN":"三名珠寶店劫匪…遭騎摩托車追趕的制裁者一網打盡…？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"지금 인터뷰로 우리 회사 시제품 설명회를 하고 있는 거야?","JPN":"インタビューで、うちの試作品の説明会をやったの？","ENG":"You're giving an impromptu product showcase for our prototypes through interviews now?","TWN":"現在是透過採訪舉辦公司的新品發表會嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"기자들이 범죄자들을 제압한 경위를 물어보기에… 겸사겸사.","JPN":"記者に犯罪者を制圧した経緯について聞かれたので……ついでに。","ENG":"The reporters asked how I stopped them… Figured I might as well demonstrate.","TWN":"記者問我事發經過…所以我就順便…"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그리고 베일, 어제 부탁한 프로토타입의 샘플링 자료일세.","JPN":"ベイル、これは昨日頼まれたプロトタイプのサンプリング資料だ。","ENG":"And Vale, here's that prototype sampling data you asked for yesterday.","TWN":"還有這個，培麗，這是你昨天拜託我的原型樣品資料。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아, 그렇지. 이틀 뒤가 프로젝트 발표일이니까.","JPN":"あら、そういえば。プロジェクトの発表が2日後だったね。","ENG":"Ah, right. We've got the presentation in two days.","TWN":"喔，對，兩天後就是專案發表日。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그런데, 꿈자리가 사나웠다는 건… 아직도 그 악몽을 꾼다는 거지?","JPN":"それにしても、夢見が悪かったって話……まだあの悪夢を見てるの？","ENG":"By the way, that nightmare again… Still having it?","TWN":"你剛剛說惡夢…你還在做那個惡夢嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"역시 심리 상담이라도 받는 편이 좋지 않겠어?","JPN":"やっぱりカウンセリングでも受けたほうがいいんじゃない？","ENG":"You really should see a therapist about that.","TWN":"要不要去做心理諮商？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…걱정 마시게. 차차 익숙해지고 있으니.","JPN":"……心配はいらん。次第に慣れてきているゆえ。","ENG":"…Don't trouble yourself. I'm getting used to it, bit by bit.","TWN":"…沒事，我已經慢慢習慣了。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"기술과 발전의 도시, 챔버에 터를 잡은 지도 1년이란 시간이 흘렀어.","JPN":"技術と発展の都市、チェンバーに定着してから、早1年。","ENG":"It's been a year since I settled here in Chamber, the city of progress and invention.","TWN":"落腳在強巴這座以科技與進步為名的城市，已經過了一年。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"침식을 딛고 미래를 지어 올린다 라는 그 어구가 마음에 들더군.","JPN":"「侵食を乗り越えて未来を築き上げる」というスローガンが気に入ったのでな。","ENG":"Their motto, \\"Build the future atop Corruption's ruins,\\" rather appealed to me.","TWN":"踩著侵蝕築起未來這句標語，讓我頗為欣賞。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 이곳을 더 살기 좋은 곳으로 만들기 위해 1년 동안 다분히 노력했네.","JPN":"それゆえ、この街をより良くすべく、この1年間惜しみなく努力してきた。","ENG":"So I gave my best this past year, hoping to make this place a little better.","TWN":"所以這一年來，我竭力讓這裡變得更美好。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔 멀리 고향 생각이 나곤 했지만, 다 지난 일이라 생각하고 묻어둔 채로 말이야.","JPN":"時折ぼんやり故郷を思い出すことはあったが、もう過ぎたことだと蓋をして。","ENG":"Now and then, my mind would drift back home, but I told myself that was all behind me.","TWN":"偶爾會想起遙遠的故鄉，但也早已將那段往事深埋。"},"stage":{"bg":"CHAMBER","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게, 전부 묻어버린 줄 알았는데 말이지.","JPN":"そうやって、すべて割り切ったつもりだったのだが。","ENG":"Or so I thought.","TWN":"我本以為自己能徹底忘掉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>이곳에서 기다리고 있어.</color>","JPN":"<color=#ff3636>ここで待っているわ。</color>","ENG":"<color=#ff3636>We're waiting here.</color>","TWN":"我們在這裡等你。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>그러니 우릴 잊지 마.</color>","JPN":"<color=#ff3636>だから私たちを忘れないで。</color>","ENG":"<color=#ff3636>So do not forget us.</color>","TWN":"所以，別忘了我們。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VOICE_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>서생.</color>","JPN":"<color=#ff3636>ショウ。</color>","ENG":"<color=#ff3636>Seosaeng.</color>","TWN":"書生。"},"stage":{"bg":"BLACKMOUNTAIN_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이번에도… 이름 한 번 물어보지 못했군.","JPN":"今回も……名は聞けずじまい、か。","ENG":"Once more… I never even asked her name.","TWN":"這次…還是沒能問出名字。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"한 건의 메시지가 있습니다.","JPN":"1件のメッセージが届いています。","ENG":"You have one new message.","TWN":"你有一則訊息："},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"생일 축하해, 서생 씨.","JPN":"お誕生日おめでとう、ショウくん。","ENG":"Happy birthday, Seosaeng.","TWN":"生日快樂，書生！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L35_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"오늘은 여러 모로 정말 기념비적인 날이지? 마침 회사에 들어온 지 정확히 1년이잖아?","JPN":"今日は色んな意味で記念すべき日だよね？　入社してちょうど1年になる日だし。","ENG":"Quite a milestone, isn't it? It's exactly one year since you joined the company.","TWN":"今天是特別的一天，不只是你加入公司滿一年的日子，"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"우리가 함께 진행한 프로젝트를 처음으로 발표하는 날이기도 하고!","JPN":"私たちみんなで進めたプロジェクトを初めて発表する日でもあるしね！","ENG":"And today's the day we unveil our first project together!","TWN":"也是我們共同參與的專案第一次正式發表！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"밤새 근무하다가 오늘 연차 썼다고 들었어. 생일 파티 준비하고 있었는데 아쉽다.","JPN":"徹夜明けで有休取ったって聞いたよ。お誕生日パーティーの準備してたのに、残念。","ENG":"I heard you pulled an all-nighter again. Shame, because I was planning a little party.","TWN":"聽說你昨晚加班一整夜，今天請假休息。真可惜，本來想今天為你慶生的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"케이크는 숙소 냉장고에 넣어뒀으니까, 생각날 때 꺼내 먹어.","JPN":"ケーキは部屋の冷蔵庫に入れておいたから、好きな時に食べて。","ENG":"Anyway, I left the cake in your fridge. Have a slice when you feel like it.","TWN":"蛋糕放在宿舍冰箱裡，想吃的時候就拿出來吃吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"늦잠 자면 안돼! 발표회 힘내! 기대할게!","JPN":"寝坊したらダメだからね！　発表会がんばって！　楽しみにしてる！","ENG":"Don't oversleep! Knock 'em dead at the presentation! I know you will!","TWN":"別睡過頭！發表會加油！期待你的發表！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버, 서니베일 과학지구, 호텔 클라인.","JPN":"チェンバー、サニーベイル科学地区、ホテルクライン。","ENG":"Chamber, Sunnyvale Science District, Hotel Klein.","TWN":"強巴 陽光谷科學園區 克萊因飯店"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국-기업 연맹 주관, 침식대책 프로젝트 발표 세미나 종료 직후.","JPN":"管理局企業連盟主催、侵食対策プロジェクト発表セミナー終了直後。","ENG":"Immediately following the Corruption Response Project seminar, hosted by the Administration-Corporate Alliance.","TWN":"管理局-企業聯盟承辦方 侵蝕策略專案發表會結束後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"아, 서생 박사님.","JPN":"ああ、ショウ博士。","ENG":"Ah, Dr. Seosaeng!","TWN":"書生博士。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"식사는 잘 하셨습니까? 저희 호텔식이 입맛에 맞으셨으면 좋을 텐데요.","JPN":"お食事はされましたか。当ホテルの食事がお口に合えばいいのですが。","ENG":"Did you enjoy your meal? I trust our hotel cuisine suited your tastes?","TWN":"餐點還合口味嗎？希望我們飯店的菜色你還滿意。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"미안하네. 본인의 입맛은 다소 까다로운 편이라서.","JPN":"すまない。某はいささか、好き嫌いが激しい方であるゆえ。","ENG":"My apologies. I'm rather particular about my food.","TWN":"抱歉，我的口味比較挑剔。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"아… 그러셨군요.","JPN":"あ……そうでしたか。","ENG":"Ah… I see.","TWN":"喔…原來如此。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"오늘 발표는 정말 감명 깊었습니다. 이 척박한 세상에 잃어버린 계절을 되찾는 위업을 고작 1년만에 이뤄내시다니 말이에요.","JPN":"本日の発表、非常に感銘を受けました。この厳しい世の中、失われた季節を取り戻すという偉業をたった1年で成し遂げるなんて……","ENG":"Your presentation today was truly inspiring. To restore the lost seasons to this barren world in just a year's time is just remarkable.","TWN":"不過博士今天的發表實在令人震撼。竟然在短短一年內，完成奪回失落季節的霸業！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"본인 혼자 이뤄낸 일은 아니오.","JPN":"某一人の力で成したことではない。","ENG":"It was not my work alone.","TWN":"並非我一人的功勞。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그리고 기상조절시스템은 아직 프로토타입이라 위업이란 표현은 아직 이른 듯 하구려.","JPN":"それに、気象調節システムはまだプロトタイプゆえ、偉業と呼ぶにはやや気が早いのではなかろうか。","ENG":"And the Weather Control System is still just a prototype. Calling it remarkable is premature.","TWN":"而且氣象調節系統還只是原型，談不上什麼霸業。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"하하, 겸손하시긴. 도시관리국이 이번 발표회를 계기로 박사님의 연구에 투자를 결정했잖습니까.","JPN":"はは、ご謙遜を。都市管理局もこの発表会を機に、博士の研究に投資を決定したではありませんか。","ENG":"Haha, ever so humble. But surely you know the City Management has decided to invest in your research because of this presentation.","TWN":"呵呵，博士你太謙虛了。城市管理局不是已經因為這次發表會，決定投資你的研究嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이만 실례하지. 그 투자자 분과 미팅 약속을 잡고 가던 참이라.","JPN":"失礼、もう行かなくては。この後、その投資家と打ち合わせの約束が控えていてな。","ENG":"Pardon me. I should be going. I have a meeting set with that investor.","TWN":"失陪了，我正要去見那位投資者。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"역시 그랬군요. 관리국이라면 서생 박사님의 역량을 일찍이 알아본 거겠죠.","JPN":"やはりそうでしたか。管理局はショウ博士のご才覚を早くから見抜いていたのでしょう。","ENG":"Ah, of course. The Administration surely saw your brilliance long before the rest of us.","TWN":"我就知道，管理局肯定早就注意到博士的能耐。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OFFICER_NPC_NULL_14","text":{"KOREA":"제가 감히 보장하건대, 박사님께선 조만간 관리국의 요직에 앉으실 겁니다.","JPN":"断言できます。博士は近いうちに、管理局の要職にお就きになります。","ENG":"Mark my words, Doctor. You'll be seated in one of the Administration's highest offices before long.","TWN":"我敢保證，你很快就會擔任管理局的重要職位。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국의 요직이라…","JPN":"管理局の要職か……","ENG":"A seat in the Administration, is it…","TWN":"管理局的重要職位…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 내가 돌아갈 일은 없겠지.","JPN":"しかし某が戻ることはなかろう。","ENG":"Yet I doubt I'll ever return.","TWN":"但我是不可能回去的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"떠나갈 때도 분명, 그럴 마땅한 이유가 있었을 테니.","JPN":"そこを離れたのも、相応の理由あってのことであろうしな。","ENG":"I left with good reason, after all.","TWN":"畢竟離開也不是一時衝動。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"오셨군요, 박사님. 만나 뵙게 되어 영광입니다.","JPN":"博士、お会いできて光栄です。","ENG":"Ah, Dr. Seosaeng. It's an honor to finally meet you in person.","TWN":"你來啦，博士。很榮幸見到你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"오늘 발표하신 프로젝트는 정말 인상 깊었어요. 개인적으로도 투자하고 싶더군요.","JPN":"本日発表されたプロジェクト、とても興味深く拝聴しました。私個人としての投資も考慮したくなるほどでした。","ENG":"Your presentation today was truly impressive. I must admit, I'd invest myself if I could.","TWN":"今天的專案發表令人印象深刻，我個人也很想投資呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"투자는 경영진과 얘기하는 편이 빠를 거요. 난 권한 없는 일개 연구원일 뿐이니.","JPN":"投資の件なら経営陣と話した方が早かろう。某は一介の研究員に過ぎぬゆえ。","ENG":"Best speak to management about that. I'm just a researcher. No authority for such things.","TWN":"投資的事去找經營層談吧，我只是個沒有決策權的研究員。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"제가 박사님을 모신 이유는 따로 있습니다. 몇 가지 전해드릴 것도 있고요.","JPN":"博士にお越しいただいた理由は別にあります。いくつかお渡ししたい物もありますし。","ENG":"I did not ask you here for that alone. There are some things I must pass along.","TWN":"其實我找博士另有目的，有些東西要交給你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이건…?","JPN":"これは……？","ENG":"What's this…?","TWN":"這是…？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"회사 직원 분들에게 여쭤보니, 끼니를 자주 거르신다더군요.","JPN":"博士は食事をよく抜かれると、会社の方から伺いまして。","ENG":"I asked around and heard you often skip meals.","TWN":"我聽說你公司的員工說，你常常不吃飯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"향토 음식이라면 입맛에 맞으실 것 같아 준비했습니다.","JPN":"郷土料理であればお口に合うかと思い、ご用意いたしました。","ENG":"So I prepared something traditional. A taste of home, so to speak.","TWN":"所以特地準備了一些家鄉料理，應該會合博士的口味。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"이 음식들의 이름을 알고 있네.","JPN":"某はこの料理の名を知っている。","ENG":"I know these dishes well.","TWN":"這些菜的名字我都知道。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 왜 그 향과 색채에 그토록 이끌린 것인지는 알다가도 모를 일이요.","JPN":"しかし、なぜその香りと色彩にそれほど惹かれたかは分からない。","ENG":"Yet why their scent and color draw me so, I can't quite say.","TWN":"只是為什麼香氣和色彩會如此牽動我的心弦，我卻說不清楚。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그 말마따나, 익숙한 고향의 음식이기 때문이겠지.","JPN":"彼の言う通り、食べ慣れた故郷の味ゆえであろう。","ENG":"It's probably because it's the familiar taste of home.","TWN":"或許因為這是熟悉的家鄉味吧。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"준비한 보람이 있었네요. 양이 제법 많다고 생각했는데 전부 드실 줄은 몰랐어요.","JPN":"用意した甲斐がありました。少し多すぎるかと思いましたが、完食してくださるとは。","ENG":"I'm glad it suited you. I didn't think you'd finish it all. It was quite a spread.","TWN":"看來特地準備是值得的。原本還擔心份量太多，沒想到你全吃完了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그대 말처럼 입맛에 맞았소. 준비해줘서 고맙구려.","JPN":"そなたの言葉どおり舌に合ったのだ。気遣い感謝する。","ENG":"Just as you said, it suited my palate. Thank you.","TWN":"確實合我口味，多謝。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"그럼 본론으로 넘어가서…","JPN":"では本題に入りましょうか。","ENG":"Now then, shall we get to the main point…?","TWN":"那我們進入正題吧…"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"이걸 봐주시겠습니까?","JPN":"こちらをご覧いただけますか？","ENG":"Would you take a look at this?","TWN":"請看這個。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"직원은 책상 아래에서 묵직해 보이는 가방을 들어 올리더군.","JPN":"職員は机の下から重たそうな鞄を持ち上げた。","ENG":"The staff lifted a heavy-looking case from beneath the table.","TWN":"對方從桌子底下拿出一個沉重的袋子。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"돈다발을 보는 건 익숙했다네. 지난 일 년 동안 날 스카우트하려는 기업은 많았으니까.","JPN":"札束は見慣れていた。この一年間、某を引き抜かんとする企業は多かったゆえ。","ENG":"I had grown used to the sight of money as many companies tried to lure me to theirs this past year.","TWN":"整袋的鈔票我早就見怪不怪，過去一年裡，有多少企業想挖角我。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"내 스스로 그곳을 떠났음에도, 관리국 또한 그들과 별반 다르지 않겠다는 생각을 잠시 했지.","JPN":"自らの足で立ち去ったというのに。管理局も彼らと大差ないのだという考えが、鞄を前にして一瞬頭をよぎった。","ENG":"So for a moment, I thought the Administration no different from the rest.","TWN":"我原想，連我自願離開的那個地方，管理局也不例外。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"허나, 가방에 들어있던 건 뜻밖의 것이었어.","JPN":"しかし、その鞄に入っていたものは某の考えていたものとは違っていた。","ENG":"Yet what lay within was something I did not expect.","TWN":"然而，袋子裡裝的卻是意想不到的東西。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"이건… 검인가?","JPN":"これは……剣か。","ENG":"A… sword?","TWN":"這是…劍？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"그렇습니다. 시니어님의 말씀을 빌리자면, 세상에 하나뿐인 검이라더군요.","JPN":"はい。シニアの言葉を借りれば、この世にたった一振りしかない剣だそうです。","ENG":"Indeed. Our Senior says it's one of a kind.","TWN":"沒錯。照Senior所說，這是世上唯一的一把劍。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"부디 받아주시길.","JPN":"どうぞお納めください。","ENG":"Please, take it.","TWN":"請博士收下。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"특이한 선물이군. 관리국답게 정교한 기술력이 엿보여.","JPN":"変わった土産だな。さすがは管理局だ。精巧な技術力が垣間見える。","ENG":"An interesting gift. The craftsmanship is typical of the Administration's handiwork.","TWN":"真特別的禮物，能看出管理局精湛的工藝。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"허나 사양하지. 검이 없어도 생활에 불편함은 없으니.","JPN":"だが遠慮させてもらおう。剣がなくとも生活に不自由はないゆえ。","ENG":"Still, I must decline. I have no use for a sword in my daily life.","TWN":"不過恕我拒收，我生活裡並不需要劍。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아, 오해하고 계시군요. 이건 선물이 아닙니다.","JPN":"ああ、誤解があるようですが、これは贈り物ではありません。","ENG":"Ah, there's been a misunderstanding. This is not a gift.","TWN":"博士誤會了，這不是禮物。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"박사님께서 직접 만들었던 물건을 돌려드리는 것뿐이니까요.","JPN":"博士がお作りになったものを、お返しするだけですから。","ENG":"We are merely returning something you made yourself.","TWN":"這只是物歸原主，因為這把劍是你親手打造的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"내가 만들었다고…?","JPN":"某が作った……？","ENG":"I made this…?","TWN":"我親手…打造的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"방금, 이걸 준 사람이 누구라고 했소?","JPN":"今、これを渡した人物が誰だと言ったかな？","ENG":"Who did you say sent this?","TWN":"你說，這把劍是誰要你交給我的？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"저희가 모시는 챔버의 시니어님입니다.","JPN":"私たちの上司であるチェンバーのシニアです。","ENG":"Our Senior here in Chamber.","TWN":"是強巴的Senior。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"난 1년 전 관리국을 떠난 몸이요.","JPN":"某は1年前に管理局を去った身。","ENG":"I left the Administration a year ago.","TWN":"但我一年前已經離開管理局。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리국 보안 절차에 따라 과거의 모든 기록과 그곳에서 겪은 모든 기억을 지웠지.","JPN":"管理局のセキュリティポリシーに従い、過去の記録とそこで経験した記憶をすべて末梢した。","ENG":"As security protocol demanded, I erased every record and memory of my time there.","TWN":"並且照管理局的安全程序，將所有過去的紀錄和記憶都消除掉。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그런데, 누구보다 규율에 엄격해야 할 관리자 나리가 내게 과거의 물건을 주라고 했다고?","JPN":"なのに、誰よりも規律を厳しく守るべき管理者殿が、某に過去の持ち物を渡すよう指示したと言うのか？","ENG":"And yet the Administrator himself sends me a piece of the past?","TWN":"究竟，最應該遵守規矩的管理者，為何會要你把過去的物品交還給我呢？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"네, 그리고 이 말씀도 함께 남기셨습니다.","JPN":"はい、伝言も預かっています。","ENG":"Yes, along with these words, too.","TWN":"是的，他還留下一句話："},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"<color=#ffd34c>과거를 잊을 수는 있어도, 지울 순 없다</color>…라고요.","JPN":"<color=#ffd34c>過去を忘れることはできても、消すことはできない</color>……と。","ENG":"<color=#ffd34c>One may forget the past, but never truly erase it.</color>","TWN":"<color=#ffd34c>過去或許可以忘記，但無法消除</color>……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"이제 당신의 물건이니, 처분은 마음대로 하셔도 됩니다.","JPN":"これはもう博士のものです。処分なさるかどうかは博士にお任せします。","ENG":"It is yours once more. Do with it what you will.","TWN":"現在它是你的了，隨你怎麼處置。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"저기, 서생 씨.","JPN":"ねえ、ショウくん。","ENG":"Hey, Seosaeng.","TWN":"書生。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아까 창고에 갖고 들어가던 거- 뭔지 물어봐도 돼?","JPN":"さっき倉庫に運んでた物って何なのか聞いてもいい？","ENG":"That thing you carried into the storage room. Mind if I ask what it is?","TWN":"方便問，剛你拿去倉庫的東西是什麼嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다신 꺼내볼 일 없는 애물단지일세.","JPN":"二度と取り出すことのないがらくただ。","ENG":"Nothing more than a keepsake I have no reason to unearth again.","TWN":"是一個我再也不想拿出來的累贅。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그래? 디자인은 멋스럽던데.","JPN":"そう？　おしゃれなデザインだったけど。","ENG":"Really? It looked pretty sleek to me.","TWN":"是喔？設計還蠻好看的。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아 참, 당신 바이크 수리 끝났으니 집 가는 길에 가져가.","JPN":"あ、バイクの修理終わったから、帰りに持ってって。","ENG":"Oh, by the way, your bike's fixed. Pick it up on your way home.","TWN":"對了，你的摩托車修好了，回去的時候記得牽走。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"본사가 침식재난으로 망하는 바람에, 그 모델 부품 구하는 게 쉽지 않더라.","JPN":"あのモデル、製造元が侵食災害で潰れたせいで部品がなかなか手に入らなくて大変だったよ。","ENG":"Took forever to find parts after the head office tanked in that Corruption disaster.","TWN":"總公司因為侵蝕災難受到毀損，這型號的零件可不好找。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"고맙네. 수리비는…","JPN":"礼を言う。修理代は……","ENG":"Thank you. As for the repair cost–","TWN":"謝啦，修理費多少…"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"됐어. 우리 사이에 수리비는 무슨. 다음부턴 좀 살살 몰아.","JPN":"水くさいわね。そんなのいらないわよ。代わりに、これからはもうちょっと優しく使うこと。","ENG":"Forget it. It's on me. Just take it easy next time.","TWN":"沒事，我們之間還談什麼錢！以後騎慢點。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"무장강도 쫓아가는 위험한 짓도 다신 하지 말고.","JPN":"武装した強盗を追いかけるような危ない真似は二度としないで。","ENG":"And no more chasing down armed robbers, got it?","TWN":"下次別再做追搶匪這種危險的事了。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"우연히 출근길과 동선이 겹친 것뿐일세.","JPN":"偶然、通勤ルートと被っただけなんだが。","ENG":"It was mere chance our paths crossed on my way in.","TWN":"只是剛好上班路上遇到而已。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"대공 미사일에 휘말리고, 강도 때려잡은 것도 우연이라고 할 거야?","JPN":"対空ミサイルに巻き込まれたり、強盗をやっつけたりしたのも偶然って言い張る気？","ENG":"Are you really going to say getting caught in an anti-air missile strike and taking down armed robbers was just a coincidence?","TWN":"這麼剛好？剛好被防空飛彈波及，剛好抓到搶匪？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"네가 다치면 마음 아파할 사람들도 좀 생각하는 게 어때?","JPN":"あなたが怪我したら悲しむ人がいるってこと、ちょっとは考えてよ。","ENG":"Try sparing a thought for the people who'd be hurt if you got yourself killed.","TWN":"拜託你想一下，要是你受傷，會有人為你傷心難過好嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"내가 다치면 마음이 아픈가?","JPN":"そなた、某が怪我すると悲しいのか？","ENG":"Tell me. Would it trouble you if I came to harm?","TWN":"如果我受傷，你會難過嗎？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"뭐…? 왜 다짜고짜 걱정하는 게 나라고 생각하는데?","JPN":"え……？　なんでそれが私だと思うの？","ENG":"Huh…? Who says I meant me?!","TWN":"蛤…？為什麼是我？"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그야 내겐 친구가 그대뿐이니까.","JPN":"友と呼べるのはそなたしかおらんゆえ。","ENG":"Well, you're the only friend I have.","TWN":"因為我只有你這個朋友。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"하, 사람 좀 사귀면서 살아. 챔버에 온 지 1년이 지났는데 아직도 그 소리야?","JPN":"はあ、もうちょっと人と関わったらどう？　チェンバーに来て1年も経つのに、まだそんなこと言ってるの？","ENG":"Hah. Try making more, will you? It's been a year since you came to Chamber and you're still saying that?","TWN":"哈，你也跟其他人相處一下吧。都來強巴一年了，還是獨來獨往的。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"미안하군. 누굴 사귄다는 건 좀처럼 익숙지 않아서.","JPN":"すまない。人との付き合いはどうも慣れんのだ。","ENG":"My apologies. I've never been good at that sort of thing.","TWN":"抱歉，我始終不習慣與人相處。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"됐다, 됐어. 사과나 들으려고 불러 세운 것도 아니니까.","JPN":"いいよもう。謝って欲しくて呼び止めたわけじゃないし。","ENG":"Ugh, forget it. Not like I cornered you for an apology.","TWN":"算了算了，我也不是要你道歉。"},"stage":{"bg":"TEHERANRO_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아. 내일 보육원에서 진행하는 과학의 날 행사 돕기로 했는데, 혹시 시간 괜찮아?","JPN":"そういえば明日、孤児院で科学の日の催しがあって手伝うことになったんだけど、ショウくんも来てくれる？","ENG":"Oh. Tomorrow's Science Day at the orphanage. Think you can lend a hand?","TWN":"對了，明天育幼院有個科學日的活動，你可以幫忙嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그러지. 고아들과 어울리는 것도 제법 익숙하니까.","JPN":"そうしよう。孤児たちとの付き合いにはもう慣れたしな。","ENG":"Of course. I'm rather used to spending time with orphans.","TWN":"可以，我倒是很習慣跟孤兒相處。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"저기… 이번엔 고아라는 표현 쓰지 말고 제대로 이름으로 불러줘야 한다? 애들은 쉽게 상처받는다고.","JPN":"あのね……孤児って言わないで、ちゃんと名前で呼んであげてね。子どもは傷つきやすいの。","ENG":"Hey… Don't call them \\"orphans.\\" Use their names, okay? Kids are sensitive.","TWN":"提醒你一下…這次去別再叫他們孤兒，要直接叫名字，知道嗎？小孩子很敏感的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그리고 리사한텐 빈말이라도 칭찬 좀 많이 해줘. 서생 씨를 좋아하니까, 분명 기뻐할 거야.","JPN":"あと、リサにはお世辞でもいいからたくさん褒め言葉をかけてあげて。あの子はショウくんのこと好きだし、きっと喜ぶと思うんだ。","ENG":"And tell Lisa she did well even if it's just to make her smile. She adores you.","TWN":"還有，多稱讚莉莎，就算只是客套話也行。她喜歡你，一定會很高興的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…알겠네.","JPN":"……分かった。","ENG":"…Very well.","TWN":"……明白。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_20"},{"id":"L50_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그럼 내일 봐!","JPN":"じゃあ明日よろしく！","ENG":"See you tomorrow then!","TWN":"那就明天見囉！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"서생 씨! 정말 미안!","JPN":"ショウくん、本当にごめん！","ENG":"Seosaeng! I'm so sorry!","TWN":"書生！不好意思！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L4_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"난 개인 잔업 때문에 회사에 남아야 할 것 같아. 보육원 혼자 가줄래? 다음에 밥 살게!","JPN":"私、残業のせいで会社にいないといけないの。孤児院には一人で行ってくれない？　後でご飯奢るから！","ENG":"I've got to stay and wrap up some work. Could you go to the orphanage alone? I'll treat you to lunch next time!","TWN":"我臨時有事要在公司加班，育幼院你自己去可以嗎？下次我請你吃飯！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"주말에도 출근인가?","JPN":"週末も出勤するのか？","ENG":"Going to work on the weekend too?","TWN":"週末還要加班？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"하아… 엄밀히 말하면 출근은 아니지. 퇴근한 적이 없으니까.","JPN":"はあ……厳密に言うと出勤じゃないけどね。だって退勤してないから。","ENG":"*Sigh…* More like I never left the office in the first place.","TWN":"哀…嚴格說不算加班，因為我根本沒下過班。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아이들은 꼭 이름으로 부르고, 칭찬 많이 해주기. 부탁해?","JPN":"子どもたちは必ず名前で呼んで、たくさん褒めてあげること。頼んだよ！","ENG":"Call the kids by name, okay? And compliment them a lot. Please?","TWN":"記得一定要叫孩子們的名字，還要多稱讚他們。交給你囉？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…그러지.","JPN":"……そうしよう。","ENG":"…So be it.","TWN":"……好。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 교외 거주지 밀집구역, 알바트로스 수녀회 산하 보육원. 과학의 날 기념 행사.","JPN":"チェンバー郊外居住地密集区域、アルバトロス修道会傘下の孤児院。科学の日の記念行事。","ENG":"Chamber's Outer Residential Zone, Orphanage under Albatross Sisterhood. Science Day event.","TWN":"強巴郊區集中區 信天翁修道院所屬育幼院 科學日活動"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHILD_NPC_NURSERY_NULL","text":{"KOREA":"이거 봐라-! 선생님한테 받았지롱!","JPN":"見て見て～！　先生にもらっちゃった！","ENG":"Look! Mr. Seosaeng gave me this!","TWN":"你看！老師送我的！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHILD_NPC_NURSERY_NULL","text":{"KOREA":"봤어? 뒤집어졌다가 스스로 돌아눕는 거.","JPN":"見た？　ひっくり返って、自分で元に戻ったよ！","ENG":"Did you see? It flips over and rights itself!","TWN":"看到沒？它翻倒後還能自己翻回來！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L16_1","type":"dialog","speaker":"CHILD_NPC_NURSERY_NULL","text":{"KOREA":"나도 이런 거 만들고 싶어!","JPN":"私もこういうの作りたい！","ENG":"I wanna make one too!","TWN":"我也想做這個！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"선생님! 저도 공부하면 이런 거 만들 수 있나요?","JPN":"先生！　私も勉強したら、こういうの作れる？","ENG":"Mr. Seosaeng! If I study hard, can I make stuff like this too?","TWN":"老師！我認真念書的話也做得出來嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"쉽지 않겠지. 그대는 집중력을 금방 잃을뿐더러, 나만큼 만드는 재주도 뛰어나지 않으니까.","JPN":"そううまくは行かんだろう。そなたはすぐ集中が切れるうえに、某ほど器用ではないからな。","ENG":"That won't be easy, I'm afraid. You lose focus too quickly and your hands are not quite skilled enough like me.","TWN":"可能不容易。因為你注意力不集中，手藝也比不上我。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"히잉…","JPN":"ふええん……","ENG":"Waaah…","TWN":"嗚嗚…"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"포기하지 않고 1년만 노력한다면… 기능을 간소화한 B타입 정도는 구현해볼 수 있을 걸세.","JPN":"諦めずに1年ほど努力すれば……機能を簡素化したBタイプぐらいは具現できるかもしれん。","ENG":"Still, if you stick with it for a year or so… you might manage a simple Type-B.","TWN":"不過，要是你能堅持一年不放棄…或許能做出簡化的B型。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"1년이나 걸려요? 난 당장 만들고 싶은데에-","JPN":"1年も～？　今すぐ作りたいのに！","ENG":"A whole year?! But I want one now!","TWN":"要一年喔？我現在就想要！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"실패를 줄이고 정교한 결과를 내기 위해선 시간이 필요한 법이지. 느릿느릿 걸어도 황소걸음이란 말이 있잖나.","JPN":"失敗を減らし、精巧な結果を出すためには、時間を要するものだ。牛の歩みも千里と言うではないか。","ENG":"If you wish to make fewer mistakes and do it well, you need time. Slow steps still reach the end of the road.","TWN":"要減少失敗，做到精準，就必須花時間。這就是所謂的慢工出細活。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"그런 말은 처음 들어보는데.","JPN":"そんな言葉初めて聞くよ～","ENG":"I've never heard that one before.","TWN":"我第一次聽到欸。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GIRL_NPC_NURSERY_NULL","text":{"KOREA":"아무튼 똑똑한 선생님이 가르쳐주세요! 열심히 배울게요!","JPN":"とにかく、頭のいい先生が教えてくれたら頑張って勉強する！","ENG":"Anyway! You'll teach me, right? I'll study super hard!","TWN":"總之，拜託聰明的老師教我，我會努力學的。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"그렇다면 이번엔 좀 더 간단한 굴뚝 청소 토끼를 만드는 법에 대해 수업을…","JPN":"では、今度はより簡単な煙突掃除うさぎの作り方について……","ENG":"Very well. Today, we'll start with something simpler. A little chimney-sweeper rabbit…","TWN":"好吧，那這次就教你做更簡單的掃煙囪兔子吧…"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_NPC_NURSERY_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"아이들이랑 놀아주느라 고생 많으세요, 박사님.","JPN":"お疲れ様です、博士。子どもたちと遊ぶのも大変でしょう。","ENG":"Thank you for playing with the children, Doctor.","TWN":"博士，謝謝你來陪孩子們玩，辛苦了。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"점심 준비가 거의 끝나가는데 같이 식사하시겠어요?","JPN":"昼食の準備がそろそろ終わりますが、博士も一緒にいかがですか？","ENG":"Lunch is nearly ready. Would you care to join us?","TWN":"午餐已經準備得差不多了，一起用餐嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"벌써 시간이 그렇게 됐구려.","JPN":"もうそんな時間か。","ENG":"Time's gotten away from me already.","TWN":"時間過得真快。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"괜찮다면 배식은 같이 돕겠네.","JPN":"よければ配食を手伝おう。","ENG":"If you don't mind, I'll help with serving.","TWN":"那我來幫忙分餐吧。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"후후, 그럼 부탁드립니다.","JPN":"ふふ、ではお願いします。","ENG":"Haha, then I leave it in your hands.","TWN":"呵呵，那就拜託你了。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_NURSERY_NULL","text":{"KOREA":"앗, 저도 선생님 도울래요!","JPN":"あ、ぼくも先生のお手伝いする！","ENG":"Wait! We'll help too!","TWN":"我也要幫老師忙！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L38_1","type":"dialog","speaker":"CHILD_NPC_NURSERY_NULL","text":{"KOREA":"나도! 같이 가!","JPN":"私も行きたい！","ENG":"Me too! Let's go!","TWN":"我也要！等我啦！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NUN_NPC_NULL_14","text":{"KOREA":"아이들이 되게 좋아하네요. 처음엔 잘난 척하는 과학아저씨라면서 싫다더니.","JPN":"みんなよく懐いていますね。最初は偉そうにしてるおじさんだとか言って嫌がっていたのに。","ENG":"They adore him. I remember when they first met him and called him a stuffy science man they didn't like.","TWN":"孩子們很喜歡你呢。一開始還很討厭你，說你是囂張的科學叔叔。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"표현을 엉뚱하게 해서 그렇지, 심성은 좋은 분이에요.","JPN":"表現が少し変わっているだけで、根はいい方です。","ENG":"He may seem stiff, but he has a good heart.","TWN":"你只是不擅表達，本性其實不錯的。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBESS_NPC_NULL_14","text":{"KOREA":"처음엔 베일 자매님께 억지로 끌려온 분인 줄 알았는데, 이젠 본인도 즐기시는 것 같고 말이죠.","JPN":"最初はベイル姉妹に無理矢理連れて来られたのかと思いましたが、今ではご本人もかなり楽しんでいらっしゃるようですし。","ENG":"I thought Vale dragged him here at first, but it seems he's come to enjoy himself.","TWN":"原本我還以為是培麗姊妹硬拉你來的，現在看來你自己也樂在其中呢。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NUN_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_AB","text":{"KOREA":"주말에 고생 많았어요, 베일.","JPN":"週末勤務お疲れ様でした、ベイル。","ENG":"Good work today, Vale.","TWN":"培麗，辛苦囉～週末還加班。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"휴, 이만하면 급한 불은 껐네요.","JPN":"ふう、ひとまずこれで何とかなりましたね。","ENG":"Phew. That should put out the worst of the fires.","TWN":"呼，總算把急事處理完了"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"벌써 시간이 많이 늦었네. 가설공사 준비 끝나는 대로 퇴근하면 될 것…","JPN":"もうこんな時間か。仮設工事の準備が終わり次第、退勤すれば……","ENG":"It's gotten late. Once the provisional work wraps up, I'll clock out–","TWN":"都這麼晚了。等臨時結構準備好後就可以下…"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_ABC","text":{"KOREA":"방금 뭐였지?","JPN":"今のは何だったんだ？","ENG":"What was that?","TWN":"剛剛是怎麼回事？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_ABC","text":{"KOREA":"잠깐 정전이 됐는데… 지진인가?","JPN":"一瞬停電したけど……地震か？","ENG":"The power flickered… Was that an earthquake?","TWN":"好像有暫時停電…是地震嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"빗소리…?","JPN":"雨の音……？","ENG":"Rain…?","TWN":"雨聲…？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_ABC","text":{"KOREA":"누가 건물 책임자 좀 불러! 건물 안으로 비가 새고 있잖아!","JPN":"誰か、オフィスの責任者を呼んでくれ！　雨漏りしてるぞ！","ENG":"Somebody get the building supervisor! It's leaking inside!","TWN":"快！誰去叫大樓負責人！雨水都滲進大樓裡了！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"…비가… 건물 안에 내리고 있네.","JPN":"……雨が……建物の中で降ってる。","ENG":"…It's… raining inside the building.","TWN":"…雨，建築物裡在下雨。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"어, 어라…?","JPN":"あ、あれ……？","ENG":"H-huh…?","TWN":"咦…？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"갑자기… 왜 이렇게 어지럽지?","JPN":"急に……めまいが……","ENG":"Why do I… feel so dizzy?","TWN":"怎麼回事…？突然覺得好暈……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};